// ============== 매칭 엔진 ==============
function normalize(s){
  return (s||'').toLowerCase().replace(/\s+/g,'').replace(/[.,!?~·/\-_]/g,'');
}
function matchKB(query, kb){
  const qn = normalize(query);
  if(!qn) return null;
  let best = null, bestScore = 0;
  kb.forEach(item=>{
    let score = 0;
    (item.q||[]).forEach(kw=>{
      const k = normalize(kw);
      if(!k) return;
      if(qn.includes(k)) score += k.length * 2;
      // partial jamo match
      else if(k.length>=3 && qn.indexOf(k.slice(0,k.length-1))>=0) score += k.length;
    });
    if(score > bestScore){ bestScore = score; best = item; }
  });
  return bestScore >= 2 ? best : null;
}
function matchArticles(query, n){
  const arts = getArticles();
  if(!arts.length) return [];
  const qn = normalize(query);
  const scored = arts.map(a=>{
    const haystack = normalize(a.t + (a.g||'') + (a.d||''));
    let s = 0;
    // token by token (for Korean, use 2-grams)
    for(let i=0;i<qn.length-1;i++){
      const bg = qn.slice(i,i+2);
      if(haystack.indexOf(bg)>=0) s++;
    }
    return { a, s };
  }).filter(x=>x.s>0).sort((a,b)=>b.s-a.s);
  return scored.slice(0, n||3).map(x=>x.a);
}

// ============== 전화번호 감지 + 자동 문의 등록 ==============
// 한국 전화번호 패턴: 010-1234-5678 / 01012345678 / 010 1234 5678 / 02-123-4567 / 0502-xxx-xxxx
const PHONE_RE = /(0(?:\d{1,2}))[\s\-.]?(\d{3,4})[\s\-.]?(\d{4})/;

function extractPhone(text){
  const m = (text||'').match(PHONE_RE);
  if(!m) return null;
  // normalize to 010-1234-5678 format
  return m[1] + '-' + m[2] + '-' + m[3];
}
// 이름 추출: "저는 김철수입니다", "김철수입니다", "김철수 라고 합니다", 2~4자 한글
function extractName(text){
  const patterns = [
    /저는\s*([가-힣]{2,4})\s*(?:입니다|이라고|라고|예요|이에요)/,
    /이름은\s*([가-힣]{2,4})/,
    /^([가-힣]{2,4})\s*(?:입니다|이라고|라고|예요|이에요)/
  ];
  for(const p of patterns){
    const m = text.match(p);
    if(m) return m[1];
  }
  return null;
}
// 가게/상호 추출: "OOO식당", "OOO고기집", "OOO매장" 등
function extractStore(text){
  const m = text.match(/([가-힣A-Za-z0-9]{2,15}(?:식당|고기집|갈비|정육식당|맛집|매장|가게))/);
  return m ? m[1] : null;
}

